parameters.text:
=Analyze this customer feedback and return ONLY valid JSON.

Customer: {{ $('Has Required Fields?').item.json.customerName }}
Product: {{ $('Has Required Fields?').item.json.product }}
Feedback: {{ $('Has Required Fields?').item.json.feedbackText }}

Return exactly these fields: sentiment, category, priority, suggestedResponse, confidence

Use only these categories: bug_report, feature_request, praise, complaint, question

parameters.jsCode:
// Stage 1: Normalize and clean feedback data
const raw = $input.first().json.body;

const normalized = {
  feedbackId: 'FB-' + Date.now(),
  customerName: (raw.name || raw.fullName || 'Anonymous').trim(),
  customerEmail: (raw.email || '').toLowerCase().trim(),
  feedbackText: (raw.feedback || raw.message || raw.body || '').trim(),
  product: (raw.product || raw.service || 'general').toLowerCase().trim(),
  source: (raw.source || 'web').toLowerCase(),
  receivedAt: new Date().toISOString()
};

normalized.hasRequiredFields = !!(normalized.customerEmail && normalized.feedbackText);

return { json: normalized };

const input = $json;
let parsed;
try {
  let raw = typeof input.output === 'string' ? input.output : JSON.stringify(input.output);
  raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(raw);
} catch (e) {
  return { json: { ...input, validationPassed: false, validationError: 'Invalid JSON in AI output' } };
}
const required = ['sentiment', 'category', 'priority', 'suggestedResponse'];
const missing = required.filter(f => !parsed[f]);
if (missing.length > 0) {
  return { json: { ...input, ...parsed, validationPassed: false, validationError: 'Missing fields: ' + missing.join(', ') } };
}
const validSentiments = ['positive', 'negative', 'neutral', 'mixed'];
const validCategories = ['bug_report', 'feature_request', 'praise', 'complaint', 'question'];
const validPriorities = ['critical', 'high', 'medium', 'low'];
const errors = [];
if (!validSentiments.includes(parsed.sentiment)) errors.push('Invalid sentiment');
if (!validCategories.includes(parsed.category)) errors.push('Invalid category');
if (!validPriorities.includes(parsed.priority)) errors.push('Invalid priority');
if (errors.length > 0) {
  return { json: { ...input, ...parsed, validationPassed: false, validationError: errors.join(', ') } };
}
return { json: { ...input, ...parsed, validationPassed: true } };
